## 7. Service layer

```typescript
// src/services/user.ts




export default class UserService {
  private logger: VextLogger;

  constructor(private app: VextApp) {
    this.logger = app.logger.child({ service: "UserService" });
  }

  /**
   * Query user list by page
   *
   * Supports keyword search (fuzzy matching by name or email) and sorting.
   */
  async findAll(options: {
    page: number;
    limit: number;
    keyword?: string;
    sortBy?: "name" | "createdAt";
    sortOrder?: "asc" | "desc";
  }): Promise<{
    items: User[];
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  }> {
    this.logger.debug(options, "Query user list");

    const db = this.app.db;
    const offset = (options.page - 1) * options.limit;

    //Construct WHERE condition
    const whereCondition = options.keyword
      ? or(
          like(users.name, `%${options.keyword}%`),
          like(users.email, `%${options.keyword}%`),
        )
      : undefined;

    // Build sort
    const orderBy =
      options.sortBy === "name"
        ? options.sortOrder === "desc"
          ? desc(users.name)
          : asc(users.name)
        : options.sortOrder === "asc"
          ? asc(users.createdAt)
          : desc(users.createdAt);

    // Query data
    const items = db
      .select()
      .from(users)
      .where(whereCondition)
      .orderBy(orderBy)
      .limit(options.limit)
      .offset(offset)
      .all();

    //Total number of queries
    const [{ total }] = db
      .select({ total: count() })
      .from(users)
      .where(whereCondition)
      .all();

    return {
      items,
      total,
      page: options.page,
      limit: options.limit,
      totalPages: Math.ceil(total / options.limit),
    };
  }

  /**
   * Query users based on ID (including article list)
   */
  async findById(id: number): Promise<(User & { posts: any[] }) | null> {
    this.logger.debug({ userId: id }, "Query user details");

    const db = this.app.db;

    const user = db.select().from(users).where(eq(users.id, id)).get();

    if (!user) return null;

    // Query the user's articles
    const userPosts = db
      .select()
      .from(posts)
      .where(eq(posts.authorId, id))
      .orderBy(desc(posts.createdAt))
      .all();

    return {
      ...user,
      posts: userPosts,
    };
  }

  /**
   * Create user
   */
  async create(data: {
    name: string;
    email: string;
    age?: number;
    role?: "admin" | "user" | "editor";
    bio?: string;
    avatarUrl?: string;
  }): Promise<User> {
    this.logger.info({ email: data.email }, "Create user");

    const db = this.app.db;

    // Check email uniqueness
    const existing = db
      .select({ id: users.id })
      .from(users)
      .where(eq(users.email, data.email))
      .get();

    if (existing) {
      this.app.throw(409, "Email has been registered", 10001);
    }

    //Insert and return the complete record
    const user = db
      .insert(users)
      .values({
        name: data.name,
        email: data.email,
        age: data.age,
        role: data.role ?? "user",
        bio: data.bio,
        avatarUrl: data.avatarUrl,
      })
      .returning()
      .get();

    this.logger.info(
      { userId: user.id, email: user.email },
      "User created successfully",
    );

    return user;
  }

  /**
   * Update user
   */
  async update(
    ID: number,
    data: {
      name?: string;
      email?: string;
      age?: number;
      bio?: string;
      avatarUrl?: string;
    },
  ): Promise<User> {
    this.logger.info({ userId: id }, "Update user");

    const db = this.app.db;

    // Check if the user exists
    const existing = db.select().from(users).where(eq(users.id, id)).get();
    if (!existing) {
      this.app.throw(404, "User does not exist");
    } // If updating mailbox, check for uniqueness
    if (data.email && data.email !== existing.email) {
      const emailTaken = db
        .select({ id: users.id })
        .from(users)
        .where(eq(users.email, data.email))
        .get();

      if (emailTaken) {
        this.app.throw(
          409,
          "The mailbox is already used by another user",
          10002,
        );
      }
    }

    //Update record
    const updated = db
      .update(users)
      .set({
        ...data,
        updatedAt: sql`datetime('now')`,
      })
      .where(eq(users.id, id))
      .returning()
      .get();

    this.logger.info({ userId: id }, "User updated successfully");

    return updated;
  }

  /**
   * Delete user
   *
   * Since ON DELETE CASCADE is set, the associated articles will be automatically deleted.
   */
  async delete(id: number): Promise<void> {
    this.logger.info({ userId: id }, "Delete user");

    const db = this.app.db;

    const existing = db
      .select({ id: users.id })
      .from(users)
      .where(eq(users.id, id))
      .get();

    if (!existing) {
      this.app.throw(404, "User does not exist");
    }

    db.delete(users).where(eq(users.id, id)).run();

    this.logger.info({ userId: id }, "User deleted successfully");
  }

  /**
   * Count the number of users
   */
  async count(): Promise<number> {
    const [{ total }] = this.app.db
      .select({ total: count() })
      .from(users)
      .all();

    return total;
  }
}
```

